create extension if not exists "uuid-ossp";
create table if not exists warehouses(id uuid primary key default uuid_generate_v4(),name text not null,username text unique not null,capacity int not null default 200,active boolean default true,splash_logo_url text,created_at timestamptz default now());
create table if not exists profiles(id uuid primary key references auth.users(id) on delete cascade,username text unique not null,role text not null check(role in('admin','warehouse')),warehouse_id uuid references warehouses(id),active boolean default true,force_password_change boolean default false,created_at timestamptz default now(),last_login_at timestamptz);
create table if not exists cargos(id uuid primary key default uuid_generate_v4(),warehouse_id uuid not null references warehouses(id) on delete cascade,recipient_name text not null,slot_no int not null,is_large boolean default false,status text default 'active' check(status in('active','delivered','return_pending','returned')),visible_in_delivered boolean default true,created_by uuid references profiles(id),delivered_by uuid references profiles(id),created_at timestamptz default now(),delivered_at timestamptz,reactivated_at timestamptz,offline_key text,sync_status text default 'synced',constraint slot_range check(slot_no between 1 and 200));
create unique index if not exists unique_active_slot_per_warehouse on cargos(warehouse_id,slot_no) where status='active';
create table if not exists delivery_archive(id uuid primary key default uuid_generate_v4(),cargo_id uuid,warehouse_id uuid not null references warehouses(id) on delete cascade,recipient_name text not null,slot_no int not null,is_large boolean not null,created_at timestamptz not null,delivered_at timestamptz not null,delivered_by uuid references profiles(id),wait_minutes int default 0,created_archive_at timestamptz default now());
create table if not exists activity_logs(id uuid primary key default uuid_generate_v4(),warehouse_id uuid references warehouses(id) on delete cascade,user_id uuid references profiles(id),action text not null,description text,cargo_id uuid,created_at timestamptz default now());
create table if not exists app_settings(id uuid primary key default uuid_generate_v4(),warehouse_id uuid references warehouses(id) on delete cascade,language text default 'tr',theme text default 'light',warning_day int default 4,danger_day int default 5,ocr_sensitivity text default 'high',updated_at timestamptz default now());
alter table warehouses enable row level security; alter table profiles enable row level security; alter table cargos enable row level security; alter table delivery_archive enable row level security; alter table activity_logs enable row level security; alter table app_settings enable row level security;
create or replace function is_admin() returns boolean language sql stable security definer as $$ select exists(select 1 from profiles where id=auth.uid() and role='admin' and active=true) $$;
create or replace function current_warehouse_id() returns uuid language sql stable security definer as $$ select warehouse_id from profiles where id=auth.uid() and active=true $$;
create policy "warehouses_read" on warehouses for select using (is_admin() or id=current_warehouse_id()); create policy "warehouses_admin_all" on warehouses for all using(is_admin()) with check(is_admin());
create policy "profiles_read" on profiles for select using (is_admin() or id=auth.uid()); create policy "profiles_admin_all" on profiles for all using(is_admin()) with check(is_admin());
create policy "cargos_access" on cargos for all using(is_admin() or warehouse_id=current_warehouse_id()) with check(is_admin() or warehouse_id=current_warehouse_id());
create policy "archive_access" on delivery_archive for all using(is_admin() or warehouse_id=current_warehouse_id()) with check(is_admin() or warehouse_id=current_warehouse_id());
create policy "logs_access" on activity_logs for all using(is_admin() or warehouse_id=current_warehouse_id()) with check(is_admin() or warehouse_id=current_warehouse_id());
create policy "settings_access" on app_settings for all using(is_admin() or warehouse_id=current_warehouse_id()) with check(is_admin() or warehouse_id=current_warehouse_id());
create or replace function next_free_slot(p_warehouse_id uuid) returns int language plpgsql security definer as $$ declare cap int; n int; begin select capacity into cap from warehouses where id=p_warehouse_id; if cap is null then cap:=200; end if; for n in 1..cap loop if not exists(select 1 from cargos where warehouse_id=p_warehouse_id and slot_no=n and status='active') then return n; end if; end loop; raise exception 'Depoda boş numara yok'; end; $$;
create or replace function deliver_cargo(p_cargo_id uuid) returns void language plpgsql security definer as $$ declare c record; waitm int; begin select * into c from cargos where id=p_cargo_id; if c.id is null then raise exception 'Kargo bulunamadı'; end if; if not(is_admin() or c.warehouse_id=current_warehouse_id()) then raise exception 'Yetkisiz işlem'; end if; if c.status<>'active' then return; end if; waitm:=greatest(0,floor(extract(epoch from(now()-c.created_at))/60)::int); update cargos set status='delivered',delivered_at=now(),delivered_by=auth.uid(),visible_in_delivered=true where id=p_cargo_id; insert into delivery_archive(cargo_id,warehouse_id,recipient_name,slot_no,is_large,created_at,delivered_at,delivered_by,wait_minutes) values(c.id,c.warehouse_id,c.recipient_name,c.slot_no,c.is_large,c.created_at,now(),auth.uid(),waitm); insert into activity_logs(warehouse_id,user_id,action,description,cargo_id) values(c.warehouse_id,auth.uid(),'delivered',c.recipient_name||' teslim edildi',c.id); end; $$;
insert into warehouses(name,username,capacity) values('Esinti Ug','Esinti Ug',200) on conflict(username) do nothing; insert into warehouses(name,username,capacity,splash_logo_url) values('Meet Kiosk','Meet Kiosk',200,'/meet-kiosk-logo.jpeg') on conflict(username) do nothing;
